# Write chunk files
for i, chunk in enumerate([chunk1, chunk2, chunk3], 1):
    p = Path(f"graphify-out/.graphify_chunk_0{i}.json")
    p.write_text(json.dumps(chunk, indent=2))
    print(f"Written chunk {i}: {len(chunk['nodes'])} nodes, {len(chunk['edges'])} edges")

# Merge all chunks
all_nodes, all_edges, all_hyperedges = [], [], []
seen_ids = set()
for i in range(1, 4):
    chunk = json.loads(Path(f"graphify-out/.graphify_chunk_0{i}.json").read_text())
    for n in chunk.get("nodes", []):
        if n["id"] not in seen_ids:
            seen_ids.add(n["id"])
            all_nodes.append(n)
    all_edges.extend(chunk.get("edges", []))
    all_hyperedges.extend(chunk.get("hyperedges", []))

merged = {"nodes": all_nodes, "edges": all_edges, "hyperedges": all_hyperedges}
Path("graphify-out/.graphify_semantic.json").write_text(json.dumps(merged, indent=2))
print(f"Merged: {len(all_nodes)} nodes, {len(all_edges)} edges, {len(all_hyperedges)} hyperedges")
